    private val cache: MutableMap<String, Map<String, Int>> = HashMap()

    private fun tableFor(baseFontName: String): Map<String, Int>? {
        cache[baseFontName]?.let { return it }
        val raw = packed[baseFontName] ?: return null
        val out = HashMap<String, Int>(raw.length / 10)
        for (record in raw.splitToSequence(';')) {
            if (record.isEmpty()) continue
            val eq = record.indexOf('=')
            if (eq < 0) continue
            val name = record.substring(0, eq)
            val w = record.substring(eq + 1).toIntOrNull() ?: continue
            out[name] = w
        }
        cache[baseFontName] = out
        return out
    }

    /** Width (1/1000 em) of [glyphName] in [baseFontName], or null if unknown. */
    public fun widthOf(baseFontName: String, glyphName: String): Int? = tableFor(baseFontName)?.get(glyphName)

    /** True iff [baseFontName] is one of the 14 names a PDF reader must support. */
    public fun isStandard14(baseFontName: String): Boolean = baseFontName in packed
